// // This module handles data hazards by determining the appropriate forwarding paths for two sources, ForwardA and ForwardB. It uses control signals indicating whether the relevant registers will be written to in the current or previous pipeline stages. Based on comparisons of register destination identifiers, it sets ForwardA and ForwardB outputs to specific values that dictate whether to use values from later pipeline stages (2'b10 for EX stage, 2'b01 for MEM stage, and 2'b00 for no forwarding) to ensure the correct data is supplied in the execution stage for dependent instructions.
module top_module(EXtoMEM_RegWrite,MEMtoWB_RegWrite,
                       EXtoMEM_RegRd,MEMtoWB_RegRd,
                       IDtoEX_RegRs,IDtoEX_RegRt,
                       ForwardA,ForwardB);input EXtoMEM_RegWrite,MEMtoWB_RegWrite;
input [4:0] EXtoMEM_RegRd,MEMtoWB_RegRd,IDtoEX_RegRs,IDtoEX_RegRt;
output reg [1:0] ForwardA,ForwardB;

always @(*)
begin

  if(EXtoMEM_RegWrite && (EXtoMEM_RegRd!=5'b00000) && (EXtoMEM_RegRd==IDtoEX_RegRs))
    ForwardA=2'b10;
  else if(MEMtoWB_RegWrite && (MEMtoWB_RegRd!=5'b00000) && (MEMtoWB_RegRd==IDtoEX_RegRs) 
          && (EXtoMEM_RegRd!=IDtoEX_RegRs || ~EXtoMEM_RegWrite))
    ForwardA=2'b01;
  else
    ForwardA=2'b00;

  if(EXtoMEM_RegWrite && (EXtoMEM_RegRd!=5'b00000) && (EXtoMEM_RegRd==IDtoEX_RegRt))
    ForwardB=2'b10;
  else if(MEMtoWB_RegWrite && (MEMtoWB_RegRd!=5'b00000) && (MEMtoWB_RegRd==IDtoEX_RegRt) 
          && (EXtoMEM_RegRd!=IDtoEX_RegRt || ~EXtoMEM_RegWrite))
    ForwardB=2'b01;
  else
    ForwardB=2'b00;  
end 

endmodule
